from flask import Flask, render_template, request, redirect, url_for
import os

app = Flask(__name__)

DATA_DIR = 'data'

# Utility functions to load data from files

def load_auctions():
    auctions = []
    try:
        with open(os.path.join(DATA_DIR, 'auctions.txt'), 'r') as file:
            for line in file:
                parts = line.strip().split('|')
                if len(parts) == 5:
                    auction_id, title, description, start_price, is_featured = parts
                    auctions.append({
                        'id': int(auction_id),
                        'title': title,
                        'description': description,
                        'start_price': float(start_price),
                        'is_featured': is_featured.lower() == 'true'
                    })
    except FileNotFoundError:
        pass
    return auctions


def load_trending_auctions():
    # Return auctions flagged as featured (or separately, if another file existed)
    auctions = load_auctions()
    trending = [a for a in auctions if a['is_featured']]
    return trending


def load_users():
    users = []
    try:
        with open(os.path.join(DATA_DIR, 'users.txt'), 'r') as file:
            for line in file:
                parts = line.strip().split('|')
                if len(parts) == 3:
                    user_id, username, balance = parts
                    users.append({
                        'id': int(user_id),
                        'username': username,
                        'balance': float(balance)
                    })
    except FileNotFoundError:
        pass
    return users


def load_bids():
    bids = []
    try:
        with open(os.path.join(DATA_DIR, 'bids.txt'), 'r') as file:
            for line in file:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    bid_id, auction_id, user_id, amount = parts
                    bids.append({
                        'id': int(bid_id),
                        'auction_id': int(auction_id),
                        'user_id': int(user_id),
                        'amount': float(amount)
                    })
    except FileNotFoundError:
        pass
    return bids


@app.route('/')
def home():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    auctions = load_auctions()
    featured_auctions = [a for a in auctions if a['is_featured']]
    trending_auctions = load_trending_auctions()
    return render_template('dashboard.html', featured_auctions=featured_auctions, trending_auctions=trending_auctions)


@app.route('/auctions')
def auctions():
    auctions_data = load_auctions()
    return render_template('auctions.html', auctions=auctions_data)


@app.route('/auction/<int:auction_id>')
def auction_detail(auction_id):
    auctions = load_auctions()
    auction = next((a for a in auctions if a['id'] == auction_id), None)
    if auction is None:
        return 'Auction not found', 404
    bids = [b for b in load_bids() if b['auction_id'] == auction_id]
    return render_template('auction_detail.html', auction=auction, bids=bids)


@app.route('/place_bid', methods=['POST'])
def place_bid():
    auction_id = int(request.form.get('auction_id'))
    user_id = int(request.form.get('user_id'))
    bid_amount = float(request.form.get('bid_amount'))

    auctions = load_auctions()
    auction = next((a for a in auctions if a['id'] == auction_id), None)
    if not auction:
        return 'Auction not found', 404

    users = load_users()
    user = next((u for u in users if u['id'] == user_id), None)
    if not user:
        return 'User not found', 404

    bids = load_bids()
    highest_bid = max([b['amount'] for b in bids if b['auction_id'] == auction_id], default=auction['start_price'])
    if bid_amount <= highest_bid:
        return f'Bid must be higher than current highest bid: {highest_bid}', 400

    # Save the new bid (appending to bids.txt)
    try:
        new_bid_id = max([b['id'] for b in bids], default=0) + 1
    except ValueError:
        new_bid_id = 1

    bid_line = f"{new_bid_id}|{auction_id}|{user_id}|{bid_amount}\n"
    with open(os.path.join(DATA_DIR, 'bids.txt'), 'a') as file:
        file.write(bid_line)

    return redirect(url_for('auction_detail', auction_id=auction_id))


if __name__ == '__main__':
    app.run(debug=True)

