from flask import Flask, render_template, redirect, url_for, request, abort
import csv
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Utility functions for loading CSV data

def load_jobs():
    jobs_file = os.path.join(DATA_DIR, 'jobs.csv')
    jobs = []
    if not os.path.exists(jobs_file):
        return jobs
    with open(jobs_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # job_id:str
            # title:int (although title is string per example, spec says int? We follow example and store string for title)
            # company_id:int
            # location:str
            # salary_min:str
            # salary_max:str
            # category:int
            # description:int (Actually description is text, spec says int but that must be a typo, will keep string)
            job = {
                'job_id': row['job_id'],
                'title': row['title'],
                'company_id': row['company_id'],
                'location': row['location'],
                'salary_min': row['salary_min'],
                'salary_max': row['salary_max'],
                'category': row['category'],
                'description': row['description'],
                'posted_date': row.get('posted_date', '')
            }
            jobs.append(job)
    return jobs


def load_companies():
    companies_file = os.path.join(DATA_DIR, 'companies.csv')
    companies = []
    if not os.path.exists(companies_file):
        return companies
    with open(companies_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # company_id:str
            # company_name:int (example shows string, spec mismatch, treat as string)
            # industry:int (treat industry as string)
            # location:int (treat location as string)
            # employee_count:str
            # description:int (treat description as string)
            company = {
                'company_id': row['company_id'],
                'company_name': row['company_name'],
                'industry': row['industry'],
                'location': row['location'],
                'employee_count': row['employee_count'],
                'description': row['description']
            }
            companies.append(company)
    return companies


def load_applications():
    applications_file = os.path.join(DATA_DIR, 'applications.csv')
    applications = []
    if not os.path.exists(applications_file):
        return applications
    with open(applications_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # application_id:str
            # job_title:int (we must get job title by job_id link)
            # company_str (company name by job_id link)
            # status:int (string)
            # applied_date:int (string)
            # will store job_id separately internally
            app = {
                'application_id': row['application_id'],
                'job_id': row['job_id'],
                'applicant_name': row['applicant_name'],
                'applicant_email': row['applicant_email'],
                'status': row['status'],
                'applied_date': row['applied_date'],
                'resume_id': row.get('resume_id', '')
            }
            applications.append(app)
    return applications


def load_resumes():
    resumes_file = os.path.join(DATA_DIR, 'resumes.csv')
    resumes = []
    if not os.path.exists(resumes_file):
        return resumes
    with open(resumes_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # resume_id:str
            # applicant_name:int (treat string)
            # applicant_email:int (treat string)
            # filename:int (treat string)
            # upload_date:int (string)
            # summary:int (string)
            resume = {
                'resume_id': row['resume_id'],
                'applicant_name': row['applicant_name'],
                'applicant_email': row['applicant_email'],
                'filename': row['filename'],
                'upload_date': row['upload_date'],
                'summary': row['summary']
            }
            resumes.append(resume)
    return resumes


def load_categories():
    categories_file = os.path.join(DATA_DIR, 'categories.csv')
    categories = []
    if not os.path.exists(categories_file):
        return categories
    with open(categories_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            categories.append({
                'category_id': row['category_id'],
                'category_name': row['category_name'],
                'description': row['description'],
            })
    return categories

# Save helpers

def save_applications(applications):
    applications_file = os.path.join(DATA_DIR, 'applications.csv')
    fieldnames = ['application_id','job_id','applicant_name','applicant_email','status','applied_date','resume_id']
    with open(applications_file, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for app in applications:
            writer.writerow(app)


def save_resumes(resumes):
    resumes_file = os.path.join(DATA_DIR, 'resumes.csv')
    fieldnames = ['resume_id','applicant_name','applicant_email','filename','upload_date','summary']
    with open(resumes_file, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for resume in resumes:
            writer.writerow(resume)

