@app.route('/apply/<job_id>', methods=['POST'])
def application_submit(job_id):
    # Expect JSON with applicant_email, applicant_name, cover_letter, resume_file
    data = request.get_json()
    if not data:
        abort(400)
    required_fields = ['applicant_email', 'applicant_name', 'cover_letter', 'resume_file']
    if not all(field in data for field in required_fields):
        abort(400)

    applications = load_applications()
    # Generate new application_id
    new_id = 1
    if applications:
        new_id = max(int(app['application_id']) for app in applications) + 1
    # Create application record
    new_app = {
        'application_id': str(new_id),
        'job_id': job_id,
        'applicant_name': data['applicant_name'],
        'applicant_email': data['applicant_email'],
        'status': 'Applied',
        'applied_date': datetime.now().strftime('%Y-%m-%d'),
        'resume_id': ''  # Not linked explicitly here
    }
    applications.append(new_app)
    save_applications(applications)
    return {'message': 'Application submitted successfully', 'application_id': new_app['application_id']}, 201

