DATA_DIR = 'data'

# Utility functions for loading CSV data

def load_jobs():
    jobs_file = os.path.join(DATA_DIR, 'jobs.csv')
    jobs = []
    if not os.path.exists(jobs_file):
        return jobs
    with open(jobs_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # job_id:str
            # title:int (although title is string per example, spec says int? We follow example and store string for title)
            # company_id:int
            # location:str
            # salary_min:str
            # salary_max:str
            # category:int
            # description:int (Actually description is text, spec says int but that must be a typo, will keep string)
            job = {
                'job_id': row['job_id'],
                'title': row['title'],
                'company_id': row['company_id'],
                'location': row['location'],
                'salary_min': row['salary_min'],
                'salary_max': row['salary_max'],
                'category': row['category'],
                'description': row['description'],
                'posted_date': row.get('posted_date', '')
            }
            jobs.append(job)
    return jobs


def load_companies():
    companies_file = os.path.join(DATA_DIR, 'companies.csv')
    companies = []
    if not os.path.exists(companies_file):
        return companies
    with open(companies_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # company_id:str
            # company_name:int (example shows string, spec mismatch, treat as string)
            # industry:int (treat industry as string)
            # location:int (treat location as string)
            # employee_count:str
            # description:int (treat description as string)
            company = {
                'company_id': row['company_id'],
                'company_name': row['company_name'],
                'industry': row['industry'],
                'location': row['location'],
                'employee_count': row['employee_count'],
                'description': row['description']
            }
            companies.append(company)
    return companies


def load_applications():
    applications_file = os.path.join(DATA_DIR, 'applications.csv')
