                'resume_id': row.get('resume_id', '')
            }
            applications.append(app)
    return applications


def load_resumes():
    resumes_file = os.path.join(DATA_DIR, 'resumes.csv')
    resumes = []
    if not os.path.exists(resumes_file):
        return resumes
    with open(resumes_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            # resume_id:str
            # applicant_name:int (treat string)
            # applicant_email:int (treat string)
            # filename:int (treat string)
            # upload_date:int (string)
            # summary:int (string)
            resume = {
                'resume_id': row['resume_id'],
                'applicant_name': row['applicant_name'],
                'applicant_email': row['applicant_email'],
                'filename': row['filename'],
                'upload_date': row['upload_date'],
                'summary': row['summary']
            }
            resumes.append(resume)
    return resumes


def load_categories():
    categories_file = os.path.join(DATA_DIR, 'categories.csv')
    categories = []
    if not os.path.exists(categories_file):
        return categories
    with open(categories_file, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            categories.append({
                'category_id': row['category_id'],
                'category_name': row['category_name'],
                'description': row['description'],
            })
    return categories

# Save helpers

def save_applications(applications):
    applications_file = os.path.join(DATA_DIR, 'applications.csv')
    fieldnames = ['application_id','job_id','applicant_name','applicant_email','status','applied_date','resume_id']
    with open(applications_file, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for app in applications:
            writer.writerow(app)


def save_resumes(resumes):
    resumes_file = os.path.join(DATA_DIR, 'resumes.csv')
    fieldnames = ['resume_id','applicant_name','applicant_email','filename','upload_date','summary']
    with open(resumes_file, 'w', newline='', encoding='utf-8') as f:
