            for line in f:
                if line.strip():
                    parts = line.strip().split(',')
                    if len(parts) >= 4:
                        username, email, phone, fullname = parts
                        users[username] = {
                            'username': username,
                            'email': email,
                            'phone': phone,
                            'fullname': fullname
                        }
