import os

DATA_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data')

# Helper functions for loading data from files following the exact field order from Section 3

def load_restaurants():
    filepath = os.path.join(DATA_DIR, 'restaurants.txt')
    restaurants = []
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) < 5:
                    continue
                restaurant = {
                    'id': int(parts[0]),
                    'name': parts[1],
                    'cuisine': parts[2],
                    'rating': float(parts[3]),
                    'address': parts[4]
                }
                restaurants.append(restaurant)
    except FileNotFoundError:
        pass
    return restaurants


def load_menu_items():
    filepath = os.path.join(DATA_DIR, 'menu_items.txt')
    menu_items = []
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) < 6:
                    continue
                item = {
                    'id': int(parts[0]),
                    'restaurant_id': int(parts[1]),
                    'name': parts[2],
                    'description': parts[3],
                    'price': float(parts[4]),
                    'is_vegetarian': parts[5] == '1'
                }
                menu_items.append(item)
    except FileNotFoundError:
        pass
    return menu_items


