    try:
        with open('data/current_weather.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    location_id = int(parts[0])
                    weather[location_id] = {
                        'location_id': location_id,
                        'location_name': parts[1],
                        'temperature': float(parts[2]),
                        'condition': parts[3],
                        'humidity': int(parts[4]),
                        'wind_speed': int(parts[5]),
                        'last_updated': parts[6]
                    }
    except Exception:
        pass
    return weather


def load_forecasts():
    forecasts = []
    try:
        with open('data/forecasts.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    forecasts.append({
                        'forecast_id': int(parts[0]),
                        'location_id': int(parts[1]),
                        'date': parts[2],
                        'high_temp': float(parts[3]),
