                        'location_name': parts[3],
                        'is_default': parts[4] == '1'
                    })
    except Exception:
        pass
    return saved


# Utility to get location name by id

def get_location_name(location_id, locations=None):
    if locations is None:
        locations = load_locations()
    for loc in locations:
        if loc['location_id'] == location_id:
            return loc['location_name']
    return ''


def get_default_location():
    saved = load_saved_locations()
    current_weather = load_current_weather()
    # Find default saved location for user_id=1
    default_saved = None
    for s in saved:
        if s['user_id'] == 1 and s['is_default']:
            default_saved = s
            break
    if default_saved:
        loc_id = default_saved['location_id']
        if loc_id in current_weather:
            cw = current_weather[loc_id]
            return {
                'location_id': cw['location_id'],
                'location_name': cw['location_name'],
                'temperature': cw['temperature'],
                'condition': cw['condition']
            }
    # fallback: first location's current weather
    if current_weather:
        first = next(iter(current_weather.values()))
        return {
            'location_id': first['location_id'],
            'location_name': first['location_name'],
            'temperature': first['temperature'],
            'condition': first['condition']
        }
    return {'location_id': 0, 'location_name': '', 'temperature': 0.0, 'condition': ''}


