@app.route('/settings', methods=['GET', 'POST'])
def settings():
    # We will keep settings in memory variable for this app instance (not persistent)
    # For demo, initialize default values
    if not hasattr(settings, 'temperature_unit'):
        settings.temperature_unit = 'Celsius'
    if not hasattr(settings, 'default_location_id'):
        # try to set default from saved locations
        saved = load_saved_locations()
        default_id = None
        for s in saved:
            if s['user_id'] == 1 and s['is_default']:
                default_id = s['location_id']
                break
        if default_id is None:
            locations = load_locations()
            default_id = locations[0]['location_id'] if locations else 0
        settings.default_location_id = default_id
    if not hasattr(settings, 'alert_notifications_enabled'):
        settings.alert_notifications_enabled = True

    locations = load_locations()
    location_list = [{'location_id': loc['location_id'], 'location_name': loc['location_name']} for loc in locations]

    if request.method == 'POST':
        temperature_unit = request.form.get('temperature_unit', 'Celsius')
        default_location_id = request.form.get('default_location_id')
        alert_notifications_enabled = request.form.get('alert_notifications_enabled') == 'on'

        if temperature_unit in ['Celsius', 'Fahrenheit', 'Kelvin']:
            settings.temperature_unit = temperature_unit
        try:
            settings.default_location_id = int(default_location_id)
        except:
            pass
        settings.alert_notifications_enabled = alert_notifications_enabled

    return render_template('settings.html',
                           temperature_unit=settings.temperature_unit,
                           default_location_id=settings.default_location_id,
                           location_list=location_list,
                           alert_notifications_enabled=settings.alert_notifications_enabled)


if __name__ == '__main__':
    app.run(debug=True, port=5000)
